def solve(ops):
    from sortedcontainers import SortedList
    # Store sorted disjoint half-open intervals as list of [start, end]
    sl = SortedList(key=lambda x: x[0])

    def add(l, r):
        nl, nr = l, r
        to_remove = []
        idx = sl.bisect_key_left(l)
        if idx > 0 and sl[idx-1][1] >= l:
            idx -= 1
        while idx < len(sl) and sl[idx][0] <= r:
            iv = sl[idx]
            nl = min(nl, iv[0]); nr = max(nr, iv[1])
            to_remove.append(iv); idx += 1
        for iv in to_remove: sl.remove(iv)
        sl.add([nl, nr])

    def query(l, r):
        idx = sl.bisect_key_right(l) - 1
        if idx < 0: return 'false'
        iv = sl[idx]
        return 'true' if iv[0] <= l and iv[1] >= r else 'false'

    def remove(l, r):
        to_remove = []; to_add = []
        idx = sl.bisect_key_left(l)
        if idx > 0 and sl[idx-1][1] > l:
            idx -= 1
        while idx < len(sl) and sl[idx][0] < r:
            iv = sl[idx]; to_remove.append(iv)
            if iv[0] < l: to_add.append([iv[0], l])
            if iv[1] > r: to_add.append([r, iv[1]])
            idx += 1
        for iv in to_remove: sl.remove(iv)
        for iv in to_add: sl.add(iv)

    results = []
    for op in ops:
        parts = op.strip().split()
        cmd = parts[0]; l, r = int(parts[1]), int(parts[2])
        if cmd == 'addRange': add(l, r)
        elif cmd == 'queryRange': results.append(query(l, r))
        else: remove(l, r)
    return '\n'.join(results)

